import { useEffect, useMemo, useState } from "react";
import {
  Container,
  Row,
  Col,
  Card,
  Form,
  Button,
  Alert,
  Badge,
  Spinner,
  Table,
} from "react-bootstrap";
import { useNavigate } from "react-router-dom";
import { updateProfile } from "../services/userService";
import { getMyOrders } from "../services/orderService";

function ProfilePage({ setUser }) {
  const navigate = useNavigate();

  const getStoredUser = () => {
    try {
      const rawUser = localStorage.getItem("user");
      if (!rawUser || rawUser === "undefined") return null;
      return JSON.parse(rawUser);
    } catch (error) {
      localStorage.removeItem("user");
      return null;
    }
  };

  const storedUser = useMemo(() => getStoredUser(), []);
  const [profile, setProfile] = useState(storedUser);
  const [formData, setFormData] = useState({
    full_name: storedUser?.full_name || "",
    phone: storedUser?.phone || "",
  });

  const [orders, setOrders] = useState([]);
  const [loadingOrders, setLoadingOrders] = useState(true);
  const [savingProfile, setSavingProfile] = useState(false);
  const [profileMessage, setProfileMessage] = useState("");
  const [profileError, setProfileError] = useState("");
  const [ordersError, setOrdersError] = useState("");

  useEffect(() => {
    const fetchOrders = async () => {
      try {
        setLoadingOrders(true);
        setOrdersError("");

        const response = await getMyOrders();

        if (response.data?.success) {
          setOrders(response.data.data || []);
        } else {
          setOrdersError("Không lấy được lịch sử mua vé");
        }
      } catch (error) {
        setOrdersError(
          error.response?.data?.message || "Lỗi khi tải lịch sử mua vé"
        );
      } finally {
        setLoadingOrders(false);
      }
    };

    fetchOrders();
  }, []);

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    setSavingProfile(true);
    setProfileMessage("");
    setProfileError("");

    try {
      const response = await updateProfile({
        full_name: formData.full_name,
        phone: formData.phone,
      });

      if (response.data?.success) {
        const updatedUser = {
          ...profile,
          ...response.data.data,
        };

        setProfile(updatedUser);
        localStorage.setItem("user", JSON.stringify(updatedUser));

        if (setUser) {
          setUser(updatedUser);
        }

        setProfileMessage("Cập nhật hồ sơ thành công");
      } else {
        setProfileError(response.data?.message || "Cập nhật thất bại");
      }
    } catch (error) {
      setProfileError(
        error.response?.data?.message || "Lỗi khi cập nhật hồ sơ"
      );
    } finally {
      setSavingProfile(false);
    }
  };

  const getPaymentBadge = (status) => {
    switch (status) {
      case "paid":
        return "success";
      case "failed":
        return "danger";
      case "refunded":
        return "secondary";
      default:
        return "warning";
    }
  };

  const getOrderBadge = (status) => {
    switch (status) {
      case "confirmed":
        return "success";
      case "cancelled":
        return "secondary";
      case "failed":
        return "danger";
      default:
        return "warning";
    }
  };

  return (
    <Container className="py-5">
      <Row className="g-4">
        <Col lg={4}>
          <Card className="shadow-sm border-0 rounded-4">
            <Card.Body className="p-4">
              <h3 className="fw-bold mb-3">Hồ sơ của tôi</h3>

              {profileError && <Alert variant="danger">{profileError}</Alert>}
              {profileMessage && (
                <Alert variant="success">{profileMessage}</Alert>
              )}

              <div className="mb-4">
                <p className="mb-2">
                  <strong>Email:</strong> {profile?.email || "Chưa có"}
                </p>
                <p className="mb-2">
                  <strong>Vai trò:</strong> {profile?.role || "customer"}
                </p>
                <p className="mb-0">
                  <strong>Trạng thái:</strong> {profile?.status || "active"}
                </p>
              </div>

              <Form onSubmit={handleUpdateProfile}>
                <Form.Group className="mb-3">
                  <Form.Label>Họ và tên</Form.Label>
                  <Form.Control
                    type="text"
                    name="full_name"
                    value={formData.full_name}
                    onChange={handleChange}
                    placeholder="Nhập họ tên"
                    required
                  />
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label>Số điện thoại</Form.Label>
                  <Form.Control
                    type="text"
                    name="phone"
                    value={formData.phone}
                    onChange={handleChange}
                    placeholder="Nhập số điện thoại"
                  />
                </Form.Group>

                <Button
                  type="submit"
                  variant="primary"
                  className="w-100"
                  disabled={savingProfile}
                >
                  {savingProfile ? "Đang lưu..." : "Lưu thay đổi"}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>

        <Col lg={8}>
          <Card className="shadow-sm border-0 rounded-4">
            <Card.Body className="p-4">
              <div className="d-flex justify-content-between align-items-center mb-3">
                <h3 className="fw-bold mb-0">Lịch sử mua vé</h3>
              </div>

              {ordersError && <Alert variant="danger">{ordersError}</Alert>}

              {loadingOrders ? (
                <div className="text-center py-5">
                  <Spinner animation="border" />
                </div>
              ) : orders.length === 0 ? (
                <div className="text-center py-5 text-muted">
                  Bạn chưa có đơn hàng nào.
                </div>
              ) : (
                <Table responsive hover className="align-middle">
                  <thead>
                    <tr>
                      <th>Mã đơn</th>
                      <th>Tổng tiền</th>
                      <th>Thanh toán</th>
                      <th>Đơn hàng</th>
                      <th>Số vé</th>
                      <th>Ngày tạo</th>
                      <th></th>
                    </tr>
                  </thead>
                  <tbody>
                    {orders.map((order) => (
                      <tr key={order.id}>
                        <td className="fw-semibold">{order.order_code}</td>
                        <td>
                          {Number(order.total_amount).toLocaleString("vi-VN")} VND
                        </td>
                        <td>
                          <Badge bg={getPaymentBadge(order.payment_status)}>
                            {order.payment_status}
                          </Badge>
                        </td>
                        <td>
                          <Badge bg={getOrderBadge(order.order_status)}>
                            {order.order_status}
                          </Badge>
                        </td>
                        <td>{order.ticket_count || 0}</td>
                        <td>
                          {new Date(order.created_at).toLocaleDateString("vi-VN")}
                        </td>
                        <td className="text-end">
                          {order.payment_status === "pending" ? (
                            <Button
                              size="sm"
                              variant="outline-primary"
                              onClick={() => navigate(`/payment/${order.id}`)}
                            >
                              Thanh toán tiếp
                            </Button>
                          ) : (
                            <Button
                              size="sm"
                              variant="outline-dark"
                              onClick={() => navigate(`/payment/${order.id}`)}
                            >
                              Xem đơn
                            </Button>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default ProfilePage;
